let exec=require("child_process").exec,promisify=require("util").promisify,execAsync=promisify(exec);async function runTests(){console.log("Running all language-related tests...");try{console.log("\n=== Running Spanish Navigation Test ==="),await execAsync("npx playwright test tests/spanish-navigation.test.js"),console.log("\n=== Running French Navigation Test ==="),await execAsync("npx playwright test tests/french-navigation.test.js"),console.log("\n=== Running Arabic Navigation Test ==="),await execAsync("npx playwright test tests/arabic-navigation.test.js"),console.log("\n=== Running Language Switching Test ==="),await execAsync("npx playwright test tests/language-switching.test.js"),console.log("\n=== All language-related tests completed successfully! ===")}catch(e){console.error("Error running tests:",e),process.exit(1)}}runTests();